import 'dart:convert';import 'package:http/http.dart' as http;import 'package:shared_preferences/shared_preferences.dart';import '../config.dart';
class ApiService {ApiService._();static final instance=ApiService._();String? token;Map<String,dynamic>? user;Future<void> restore()async{final p=await SharedPreferences.getInstance();token=p.getString('token');user=jsonDecode(p.getString('user')??'null');}Future<dynamic> request(String path,{String method='GET',Map<String,dynamic>? body,bool auth=true})async{final response=await http.Request(method,Uri.parse('${Config.apiUrl}$path'))..headers.addAll({'Content-Type':'application/json',if(auth&&token!=null)'Authorization':'Bearer $token'})..body=body==null?'':jsonEncode(body);final streamed=await response.send();final text=await streamed.stream.bytesToString();final data=text.isEmpty?null:jsonDecode(text);if(streamed.statusCode>=400)throw Exception(data?['message']??'Erro na API');return data;}Future<void> login(String email,String password)async{final data=await request('/auth/login',method:'POST',body:{'email':email,'password':password},auth:false);token=data['token'];user=data['user'];final p=await SharedPreferences.getInstance();await p.setString('token',token!);await p.setString('user',jsonEncode(user));}Future<void> logout()async{token=null;user=null;final p=await SharedPreferences.getInstance();await p.clear();}Future<List<dynamic>> tables()async=>await request('/tables');Future<List<dynamic>> products()async=>await request('/catalog/products');Future<Map<String,dynamic>> openTable(String id)async=>await request('/tables/$id/open',method:'POST',body:{});Future<void> closeTable(String id)async=>await request('/tables/$id/close',method:'POST',body:{'serviceFeePercent':10});Future<void> createOrder(String tabId,List<Map<String,dynamic>> items)async=>await request('/orders',method:'POST',body:{'tabId':tabId,'items':items});}
